export const RISK_ORDER = {
    LOW: 0,
    MEDIUM: 1,
    HIGH: 2,
    CRITICAL: 3,
};
export function maxRisk(a, b) {
    return RISK_ORDER[a] >= RISK_ORDER[b] ? a : b;
}
